<?php defined('ABSPATH') || exit; class FounderKit_Admin { private static ?FounderKit_Admin $instance=null; public static function instance(): self { if(!self::$instance) self::$instance=new self(); return self::$instance; } public function __construct(){ add_action('admin_menu',[$this,'register_menu']); add_action('admin_enqueue_scripts',[$this,'enqueue_assets']); add_filter('plugin_action_links_'.FOUNDERKIT_BASENAME,[$this,'plugin_links']); do_action('founderkit_admin_init'); } public function register_menu(): void { do_action('founderkit_before_register_menu'); add_menu_page(__('FounderKit','founderkit'),__('FounderKit','founderkit'),'manage_founderkit','founderkit',[$this,'page_dashboard'],'dashicons-superhero-alt',58); do_action('founderkit_after_main_menu_registered'); add_submenu_page('founderkit',__('Dashboard','founderkit'),__('Dashboard','founderkit'),'manage_founderkit','founderkit',[$this,'page_dashboard']); do_action('founderkit_after_dashboard_submenu_registered'); add_submenu_page('founderkit',__('Blocks','founderkit'),__('Blocks','founderkit'),'manage_founderkit','founderkit-blocks',[$this,'page_blocks']); do_action('founderkit_after_blocks_submenu_registered'); add_submenu_page('founderkit',__('Addons','founderkit'),__('Addons','founderkit'),'manage_founderkit','founderkit-addons',[$this,'page_addons']); do_action('founderkit_after_addons_submenu_registered'); add_submenu_page('founderkit',__('License','founderkit'),__('License','founderkit'),'manage_founderkit','founderkit-license',[$this,'page_license']); do_action('founderkit_after_license_submenu_registered'); add_submenu_page('founderkit',__('Settings','founderkit'),__('Settings','founderkit'),'manage_founderkit','founderkit-settings',[$this,'page_settings']); do_action('founderkit_after_settings_submenu_registered'); do_action('founderkit_after_register_menu'); } public function enqueue_assets(string $hook): void { do_action('founderkit_before_enqueue_admin_assets',$hook); $should_load=apply_filters('founderkit_should_load_admin_assets',strpos($hook,'founderkit')!==false,$hook); if(!$should_load) return; $style_deps=apply_filters('founderkit_admin_style_deps',[]); wp_enqueue_style('founderkit-admin',FOUNDERKIT_URL.'admin/assets/css/admin.css',$style_deps,FOUNDERKIT_VERSION); $script_deps=apply_filters('founderkit_admin_script_deps',['jquery']); wp_enqueue_script('founderkit-admin',FOUNDERKIT_URL.'admin/assets/js/admin.js',$script_deps,FOUNDERKIT_VERSION,true); if(strpos($hook,'founderkit-license')!==false){ wp_enqueue_script('founderkit-license',FOUNDERKIT_URL.'admin/assets/js/license.js',['jquery'],FOUNDERKIT_VERSION,true); } $data=['ajaxUrl'=>admin_url('admin-ajax.php'),'nonce'=>wp_create_nonce('founderkit_nonce'),'strings'=>['saved'=>__('Settings saved!','founderkit'),'error'=>__('Something went wrong.','founderkit')]]; $data=apply_filters('founderkit_admin_localized_data',$data); wp_localize_script('founderkit-admin','fkAdmin',$data); do_action('founderkit_after_enqueue_admin_assets',$hook); } public function page_dashboard(): void { do_action('founderkit_before_page_dashboard'); require FOUNDERKIT_PATH.'admin/views/dashboard.php'; do_action('founderkit_after_page_dashboard'); } public function page_blocks(): void { do_action('founderkit_before_page_blocks'); require FOUNDERKIT_PATH.'admin/views/blocks.php'; do_action('founderkit_after_page_blocks'); } public function page_addons(): void { do_action('founderkit_before_page_addons'); require FOUNDERKIT_PATH.'admin/views/addons.php'; do_action('founderkit_after_page_addons'); } public function page_settings(): void { do_action('founderkit_before_page_settings'); require FOUNDERKIT_PATH.'admin/views/settings.php'; do_action('founderkit_after_page_settings'); } public function page_license(): void { if(!current_user_can('manage_founderkit')){ wp_die(__('Unauthorized','founderkit')); } do_action('founderkit_before_page_license'); require FOUNDERKIT_PATH.'admin/views/license.php'; do_action('founderkit_after_page_license'); } public function plugin_links(array $links): array { $links=apply_filters('founderkit_plugin_action_links',$links); return array_merge(['<a href="'.admin_url('admin.php?page=founderkit-settings').'">'.__('Settings','founderkit').'</a>'],$links); } }
